  6→  "required": ["trace_id", "timestamp", "plant_id", "state_snapshot", "action_proposed", "action_applied", "outcome"],
  7→  "properties": {
  8→    "trace_id": {
  9→      "type": "string",
 10→      "description": "Unique identifier for this trace entry"
