 19→      "description": "Identifier of the plant"
 20→    },
 21→    "controller_version": {
 22→      "type": "string",
 23→      "description": "Version/hash of the active controller configuration"
 24→    },
 25→    "state_snapshot": {
 26→      "type": "object",
 27→      "description": "Belief state at decision time (or hash + artifact pointer for large states)",
 28→      "properties": {
