 30→        "artifact_path": { "type": "string" },
 31→        "inline": { "type": "object", "additionalProperties": true }
 32→      }
 33→    },
 34→    "directive": {
 35→      "description": "The LLM's control directive θ_t (ref: action.schema.json)",
 36→      "type": "object",
 37→      "additionalProperties": true
 38→    },
 39→    "action_proposed": {
 40→      "type": "object",
 41→      "description": "Controller's proposed action before safety filtering",
 42→      "additionalProperties": true
 43→    },
 44→    "action_applied": {
 45→      "type": "object",
 46→      "description": "Actual action applied after safety shield filtering",
 47→      "additionalProperties": true
 48→    },
 49→    "shield": {
 50→      "type": "object",
 51→      "description": "Safety shield results",
 52→      "properties": {
 53→        "feasible": {
 54→          "type": "boolean",
 55→          "description": "Whether the shield found a feasible safe action"
 56→        },
 57→        "modification_magnitude": {
 58→          "type": "number",
 59→          "description": "||u_safe - u_proposed|| — how much the shield modified the action"
 60→        },
 61→        "certificate": {
 62→          "type": "object",
 63→          "description": "Safety certificate proving constraint satisfaction",
 64→          "additionalProperties": true
 65→        },
 66→        "fallback_used": {
 67→          "type": "boolean",
 68→          "default": false,
 69→          "description": "Whether emergency fallback was activated"
 70→        }
 71→      }
 72→    },
 73→    "constraints_checked": {
 74→      "type": "array",
 75→      "items": {
 76→        "type": "object",
 77→        "required": ["constraint_id", "satisfied"],
 78→        "properties": {
 79→          "constraint_id": { "type": "string" },
 80→          "satisfied": { "type": "boolean" },
 81→          "value": { "description": "Measured value for the constraint" },
 82→          "threshold": { "description": "Constraint threshold" }
 83→        }
 84→      }
 85→    },
 86→    "outcome": {
 87→      "type": "object",
 88→      "required": ["success"],
 89→      "properties": {
 90→        "success": {
 91→          "type": "boolean",
 92→          "description": "Whether the action succeeded"
 93→        },
 94→        "observation_after": {
 95→          "type": "object",
 96→          "description": "Plant observation after action",
 97→          "additionalProperties": true
 98→        },
 99→        "error": {
100→          "type": ["string", "null"],
101→          "description": "Error message if action failed"
102→        }
103→      }
104→    },
105→    "evaluator_metrics": {
106→      "type": "object",
107→      "description": "Micro-metrics scored by evaluator for this tick",
108→      "properties": {
109→        "cost": { "type": "number" },
110→        "constraint_violations": { "type": "integer" },
111→        "latency_ms": { "type": "number" },
112→        "robustness_indicator": { "type": "number" }
113→      },
114→      "additionalProperties": true
115→    },
116→    "egri": {
117→      "type": "object",
118→      "description": "EGRI loop context (if this trace is part of an improvement trial)",
119→      "properties": {
120→        "trial_id": { "type": "string" },
121→        "parent_state": { "type": "string" },
122→        "mutation_operator": { "type": "string" },
123→        "decision": {
124→          "type": "string",
125→          "enum": ["promoted", "discarded", "branched", "escalated", "pending"]
126→        }
127→      }
128→    }
129→  }
130→}
